    public void testLinearOptimizationWithMixedConstraints() {
        StepDefs stepDefs = new StepDefs();

        // Given a linear objective function with coefficients [2, 6, 7] and constant term 0
        stepDefs.a_linear_objective_function_with_coefficients_and_constant_term("2, 6, 7", 0.0);

