        stepDefs.the_variables_are_not_restricted_to_non_negative_values();

        // And the following linear constraints:
        java.util.List<java.util.List<String>> constraintsTable = new java.util.ArrayList<>();
        java.util.List<String> header = java.util.Arrays.asList("coefficients", "relationship", "value");
        java.util.List<String> row1 = java.util.Arrays.asList("1, 2, 1", "LEQ", "2");
        java.util.List<String> row2 = java.util.Arrays.asList("-1, 1, 1", "LEQ", "-1");
        java.util.List<String> row3 = java.util.Arrays.asList("2, -3, 1", "LEQ", "-1");
        constraintsTable.add(header);
        constraintsTable.add(row1);
        constraintsTable.add(row2);
        constraintsTable.add(row3);

        stepDefs.the_following_linear_constraints(constraintsTable);

        // When the simplex solver optimizes the objective function
        stepDefs.the_simplex_solver_optimizes_the_objective_function();

        // Then the solution point at index 0 should be greater than 0.0
        try {
            stepDefs.the_solution_point_at_index_should_be_greater_than(0, 0.0);
