            stepDefs.the_solution_point_at_index_should_be_greater_than(1, 0.0);
        } catch (AssertionError e) {
            System.out.println("Assertion failed for index 1: " + e.getMessage());
        }

        // And the solution point at index 2 should be less than 0.0
        try {
            stepDefs.the_solution_point_at_index_should_be_less_than(2, 0.0);
        } catch (AssertionError e) {
            System.out.println("Assertion failed for index 2: " + e.getMessage());
        }

        // And the objective value should be 2.0
        try {
            stepDefs.the_objective_value_should_be(2.0);
        } catch (AssertionError e) {
            System.out.println("Assertion failed for objective value: " + e.getMessage());
        }
    }
}

